+                 collected_ts, tool_name, calls, errors, cluster, capabilities_json, complexity, \
+                 latency_avg_ms, latency_min_ms, latency_max_ms, latency_p50_ms, latency_p95_ms, latency_p99_ms, latency_is_slow\
