+    let mut seeds = [
+        ms_f64_to_u64(p50_ms),
+        ms_f64_to_u64(avg_ms),
+        ms_f64_to_u64(p95_ms),
+        ms_f64_to_u64(p99_ms),
+    ];
+    if seeds.iter().all(|v| *v == 0) {
+        seeds = [1, 1, 1, 1];
+    }
+    while out.len() < LATENCY_HISTORY {
+        for value in &seeds {
+            if out.len() >= LATENCY_HISTORY {
+                break;
+            }
+            out.push_back(*value);
+        }
+    }
+    out
+}
